@RestController
@RequestMapping("/api")
public class HealthController {

    @Autowired private DataSource dataSource;
    @Autowired private RedisTemplate<String, String> redisTemplate;

    @GetMapping("/health")
    public ResponseEntity<Map<String, Object>> health() {
        Map<String, Object> result = new LinkedHashMap<>();

        // DB ping
        try (Connection conn = dataSource.getConnection()) {
            conn.isValid(1);
            result.put("db", "ok");
        } catch (Exception e) {
            result.put("db", "fail: " + e.getMessage());
        }

        // Redis ping
        try {
            String pong = redisTemplate.getConnectionFactory()
                .getConnection().ping();
            result.put("redis", "ok".equalsIgnoreCase(pong) ? "ok" : pong);
        } catch (Exception e) {
            result.put("redis", "fail: " + e.getMessage());
        }

        boolean healthy = "ok".equals(result.get("db")) && "ok".equals(result.get("redis"));
        result.put("status", healthy ? "UP" : "DOWN");

        return ResponseEntity
            .status(healthy ? 200 : 503)
            .body(result);
    }
}
```

**응답 예시:**
```json
{ "db": "ok", "redis": "ok", "status": "UP" }
```

의존성 확인: `spring-boot-starter-data-redis`, `spring-boot-starter-jdbc` 필요.

```java
@RestController
@RequestMapping("/api")
@RequiredArgsConstructor
public class HealthController {

    private final DataSource dataSource;
    private final StringRedisTemplate redisTemplate;

    @GetMapping("/health")
    public ResponseEntity<Map<String, Object>> health() {
        Map<String, Object> result = new LinkedHashMap<>();
        result.put("db", ping(() -> {
            try (Connection c = dataSource.getConnection()) {
                c.isValid(1);
            }
        }));
        result.put("redis", ping(() -> redisTemplate.opsForValue().get("__health__")));
        boolean ok = result.values().stream().allMatch("ok"::equals);
        return ResponseEntity.status(ok ? 200 : 503).body(result);
    }

    private String ping(ThrowingRunnable fn) {
        try { fn.run(); return "ok"; } catch (Exception e) { return "error: " + e.getMessage(); }
    }

    @FunctionalInterface
    interface ThrowingRunnable { void run() throws Exception; }
}
```

응답 예시:
```json
{"db":"ok","redis":"ok"}
```
